/// <summary>
///
/// </summary>
[SysClientCacheDataMethodAttribute(true)]
public static str salesAgreementId()
{
    str salesAgreement = SysComputedColumn::returnField(
    dataentityviewstr(SalesInvoiceLineV3Entity),
    dataEntityDataSourceStr(SalesInvoiceLineV3Entity, CustInvoiceTrans), 
    fieldStr(CustInvoiceTrans, SalesId));

    return strFmt(@"
    (select top 1 SALESNUMBERSEQUENCE
     from AGREEMENTHEADER a
     join SALESTABLE ST on ST.MATCHINGAGREEMENT = a.RECID
     where ST.SalesId = %1)", salesAgreement);

}
